import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cuda_src = """
#include <torch/extension.h>
#include <cuda_runtime.h>

__global__ void fused_conv_relu_bias_kernel(
    const float* input, const float* weight, const float* bias,
    float* output, int N, int C_out, int C_in, int H, int W, int K) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N * C_out * H * W;
    if (idx >= total) return;
    int w = idx % W; int h = (idx / W) % H;
    int co = (idx / (H * W)) % C_out; int n = idx / (C_out * H * W);
    float sum = 0.0f;
    int pad = K / 2;
    for (int ci = 0; ci < C_in; ci++)
        for (int kh = 0; kh < K; kh++)
            for (int kw = 0; kw < K; kw++) {
                int ih = h + kh - pad, iw = w + kw - pad;
                if (ih >= 0 && ih < H && iw >= 0 && iw < W)
                    sum += input[((n * C_in + ci) * H + ih) * W + iw]
                         * weight[((co * C_in + ci) * K + kh) * K + kw];
            }
    sum += bias[co];  // fused bias
    output[idx] = sum > 0.0f ? sum : 0.0f;  // fused ReLU
}

torch::Tensor fused_conv_relu_bias(torch::Tensor input, torch::Tensor weight, torch::Tensor bias) {
    int N = input.size(0), C_in = input.size(1), H = input.size(2), W = input.size(3);
    int C_out = weight.size(0), K = weight.size(2);
    auto output = torch::empty({N, C_out, H, W}, input.options());
    int total = N * C_out * H * W;
    fused_conv_relu_bias_kernel<<<(total+255)/256, 256>>>(
        input.data_ptr<float>(), weight.data_ptr<float>(), bias.data_ptr<float>(),
        output.data_ptr<float>(), N, C_out, C_in, H, W, K);
    return output;
}
"""

cpp_src = "torch::Tensor fused_conv_relu_bias(torch::Tensor, torch::Tensor, torch::Tensor);"
fusion_mod = load_inline(name='fusion', cpp_sources=cpp_src, cuda_sources=cuda_src,
                         functions=['fused_conv_relu_bias'])

class ModelNew(nn.Module):
    def __init__(self, in_channels, out_channels, kernel_size):
        super().__init__()
        self.weight = nn.Parameter(torch.randn(out_channels, in_channels, kernel_size, kernel_size))
        self.bias = nn.Parameter(torch.zeros(out_channels))

    def forward(self, x):
        return fusion_mod.fused_conv_relu_bias(x, self.weight, self.bias)
